class InvoiceTotalModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.rlm = dspy.RLM(dspy.Signature('invoice: str -> total_cents: int', 'Read a free-text invoice line and compute the grand total in whole cents.'))

    def forward(self, **inputs):
        result = self.rlm(**inputs)
        return dspy.Prediction(total_cents=result.total_cents)
